if ([401, 504].includes(pm.response.code)) {
    // in case of some error , we need to wait 5s and start again
    console.warn("resending same request after 5s")
    var endTime = new Date().getTime() + 5000;
    while (new Date().getTime() < endTime) { }
    postman.setNextRequest(pm.info.requestId);
} else {
    pm.test("success reponse code", () => {
        pm.expect(pm.response.code, "received code "+pm.response.code+" with status "+pm.response.status).to.be.oneOf([200, 201, 202, 204]);
    });
}

